+	now := time.Now().UTC()
+	return SessionMeta{
+		ID:              s.id,
+		ProfileID:       s.profile.ID(),
+		Model:           s.profile.Model(),
+		Config:          s.cfg,
+		EnvInfo:         s.envInfo,
+		CreatedAt:       now,
+		UpdatedAt:       now,
+		TurnCount:       s.turns,
+		LastInputTokens: s.contextMgr.LastInputTokens(),
+	}
+}
