+	}
+	var got SessionMeta
+	if err := json.Unmarshal(data, &got); err != nil {
+		t.Fatalf("unmarshal: %v", err)
+	}
+	if got.ID != orig.ID {
+		t.Fatalf("id: got %q want %q", got.ID, orig.ID)
