+	}
+	if got.Model != orig.Model {
+		t.Fatalf("model: got %q want %q", got.Model, orig.Model)
+	}
+	if got.TurnCount != orig.TurnCount {
+		t.Fatalf("turn_count: got %d want %d", got.TurnCount, orig.TurnCount)
+	}
