+func TestListSessionMetas_SortedByUpdatedAt(t *testing.T) {
+	dir := t.TempDir()
+
+	meta1 := testSessionMeta()
+	meta1.ID = "01JTEST_META_00000000001"
+	meta1.UpdatedAt = time.Date(2025, 1, 15, 10, 0, 0, 0, time.UTC)
