+		t.Fatalf("list[0].id: got %q want %q", list[0].ID, meta2.ID)
+	}
+	if list[1].ID != meta3.ID {
+		t.Fatalf("list[1].id: got %q want %q", list[1].ID, meta3.ID)
+	}
